// Validate and process input data
const { answers = {}, current_question = 0, flow_type = '' } = $input.all()[0].json;

// Basic validation
if (!flow_type || !['destination_inspiration', 'trip_planning'].includes(flow_type)) {
  throw new Error('Invalid flow_type');
}

if (current_question < 1) {
  throw new Error('current_question must be >= 1');
}

// Calculate progress
const questionCount = Object.keys(answers).length;
const maxQuestions = flow_type === 'destination_inspiration' ? 16 : 11;
const progress = Math.round((questionCount / maxQuestions) * 100);

// Format answers for Alfie
const answersText = Object.entries(answers)
  .map(([q, a]) => `Q${q}: ${a}`)
  .join('\n');

// Determine conversation stage
let stage = 'beginning';
if (progress > 70) stage = 'nearing_end';
else if (progress > 30) stage = 'middle';

return {
  flow_type,
  current_question,
  progress,
  stage,
  answersText,
  maxQuestions,
  questionCount
};

